import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"4. Commencement Date And Period Of Operation","description":"","frontmatter":{"title":"4. Commencement Date And Period Of Operation","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","parental-leave","wages","preliminary"]},"headers":[],"relativePath":"ebas/mspp/operation/4-commencement-date-and-period-of-operation.md","filePath":"ebas/mspp/operation/4-commencement-date-and-period-of-operation.md"}'),n={name:"ebas/mspp/operation/4-commencement-date-and-period-of-operation.md"};function i(s,e,m,p,d,l){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_4-commencement-date-and-period-of-operation" tabindex="-1">4. Commencement Date And Period Of Operation <a class="header-anchor" href="#_4-commencement-date-and-period-of-operation" aria-label="Permalink to &quot;4. Commencement Date And Period Of Operation&quot;">​</a></h1><p><strong>a.</strong> This Agreement shall come into effect seven days from the date of approval by Fair Work Commission. Wages come into operation from the beginning of the first full pay period commencing on or after 1 December 2021.</p><p><strong>b.</strong> In this Agreement, non-wage related matters (excluding wages and allowances) will come into effect from 21 December 2021, notwithstanding, that the entitlement will be applied seven days from the date of approval by the Fair Work Commission. Example: An Employee engaged by the Employer at 21 December 2021, is entitled to 14 weeks of paid parental leave from that date if they are the primary carer. Once the Agreement becomes operative, the Employee will be entitled to be paid 4 weeks paid parental leave for the primary carer.</p><p><strong>c.</strong> <a href="/eba/ebas/mspp/operation/6-savings-clause.html">Clause 6.15</a> of <a href="/eba/ebas/mspp/schedules/3-classification-descriptors-and-higher-qualification-allowanc.html">Schedule 3</a> and <a href="/eba/ebas/mspp/schedules/11-progression-of-medical-scientists-from-grade-1-to-grade-2-at.html">Schedule 11</a> (Medical Scientist Progression from Grade 1 to Grade 2) will apply as of 1 December 2017 or the operative date of the Agreement which ever is the later date.</p><p><strong>d.</strong> This Agreement will nominally expire on 30 November 2025 or 4 years from the date of approval by Fair Work Commission, whichever is the earlier.</p><p><strong>e.</strong> The Agreement will continue to operate after the nominal expiry date in accordance with the provisions of the Fair Work Act 2009 (Cth).</p><p><strong>f.</strong> The negotiations for a replacement agreement shall commence in February 2025, provided that any claim made during this period is not supported by industrial action.</p><p>Plain language terms: start date, nominal expiry, operative date.</p>',8)])])}const f=a(n,[["render",i]]);export{h as __pageData,f as default};
